#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 6 (Layer 3, entrega 1): secuenciador conv1+pool1
# CON npu_array integrado en la ruta de datos.
#   conv1 1->8 canales 16x16 padding same, ReLU, requantize HXQ8, maxpool 2x2
# Criterio: firma de pool1 identica al oraculo (0xE4C64381), sin cambio
# respecto a la version con MAC interno: equivalencia demostrada.
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere Pasos 1-3.
# Linea esperada al final:
# NPU PASO6 OK L3 SEQ_CONV1+ARRAY PASS MUTACIONES 5/5 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/model/npu_weights.hex" ] || [ ! -f "$DIR/rtl/npu_array.vhd" ]; then
  echo "FALLO: faltan Pasos 1-3 en $DIR"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/rtl/npu_seq_conv1.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_seq_conv1.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_l3_conv1.py"

EOF
base64 -d << "EOF" > "$DIR/run_l3_seq.sh"

EOF
chmod +x "$DIR/run_l3_seq.sh"
cd "$DIR"
bash run_l3_seq.sh
)
